            a {{
                display: inline-block;
                margin-top: 20px;
                background-color: #fff;
                color: #667eea;
                padding: 10px 20px;
                text-decoration: none;
                border-radius: 5px;
                font-weight: bold;
            }}
            a:hover {{ background-color: #f0f0f0; }}
        &lt;/style&gt;
    &lt;/head&gt;
    &lt;body&gt;
        &lt;div class="card"&gt;
            &lt;div class="emoji"&gt;{t['emoji']}&lt;/div&gt;
            &lt;h1&gt;{t['name']}&lt;/h1&gt;
            &lt;p&gt;{t['info']}&lt;/p&gt;
            &lt;a href="/"&gt;← Zurück&lt;/a&gt;
