from flask import Flask, render_template, request

app = Flask(__name__)

@app.route('/')
def taschenrechner():
    return render_template('taschenrechner.html')

@app.route('/berechnen', methods=['POST'])
def berechnen():
    try:
        zahl1 = float(request.form.get('zahl1', 0))
        zahl2 = float(request.form.get('zahl2', 0))
        operator = request.form.get('operator', '+')

        if operator == '+':
            result = zahl1 + zahl2
        elif operator == '-':
            result = zahl1 - zahl2
        elif operator == '*':
            result = zahl1 * zahl2
        elif operator == '/':
            if zahl2 == 0:
                return render_template('taschenrechner.html',
                                     error='Division durch 0 ist nicht möglich! 😱')
            result = zahl1 / zahl2
        else:
            result = 0

        return render_template('taschenrechner.html',
                             zahl1=zahl1,
                             zahl2=zahl2,
                             operator=operator,
                             result=result)

    except ValueError:
        return render_template('taschenrechner.html',
                             error='Bitte gib gültige Zahlen ein!')

if __name__ == '__main__':
