                                &lt;/td&gt;
                            &lt;/tr&gt;
                        {% endfor %}
                    &lt;/tbody&gt;
                &lt;/table&gt;
            &lt;/div&gt;
        {% else %}
            &lt;div class="alert alert-warning"&gt;
                ❌ Keine Bücher gefunden. Versuche eine andere Suche!
            &lt;/div&gt;
        {% endif %}
    &lt;/div&gt;
&lt;/body&gt;
&lt;/html&gt;
Wie es funktioniert: - request.args.get('q') holt den Suchterm aus der URL - LIKE %...% findet den Term überall im Text - Die Form nutzt GET-Method (Suchparameter sind in der URL sichtbar) - Sternsymbole zeigen die Bewertung visuell

