    &lt;link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css" rel="stylesheet"&gt;
    &lt;style&gt;
        .erledigt {
            text-decoration: line-through;
            color: #6c757d;
        }
    &lt;/style&gt;
&lt;/head&gt;
&lt;body&gt;
    &lt;div class="container mt-4"&gt;
        &lt;h1&gt;✅ Meine To-Do-Liste&lt;/h1&gt;

        &lt;!-- Flash Messages --&gt;
        {% with messages = get_flashed_messages(with_categories=true) %}
            {% if messages %}
                {% for category, message in messages %}
                    &lt;div class="alert alert-{{ category }} alert-dismissible fade show"&gt;
                        {{ message }}
                        &lt;button type="button" class="btn-close" data-bs-dismiss="alert"&gt;&lt;/button&gt;
                    &lt;/div&gt;
                {% endfor %}
            {% endif %}
        {% endwith %}

        &lt;!-- Neuer Eintrag Button --&gt;
        &lt;a href="/neu" class="btn btn-success mb-3"&gt;➕ Neue Aufgabe&lt;/a&gt;

        &lt;!-- Statistiken --&gt;
        &lt;div class="alert alert-info mb-3"&gt;
            &lt;strong&gt;📊 Statistiken:&lt;/strong&gt;
            {{ gesamt }} insgesamt
            | {{ fertig }} erledigt
            | {{ offen }} noch offen
        &lt;/div&gt;

        &lt;!-- Filter Buttons --&gt;
        &lt;div class="btn-group mb-3" role="group"&gt;
            &lt;a href="/?filter=alle" class="btn btn-outline-primary {% if filter == 'alle' %}active{% endif %}"&gt;
                Alle ({{ gesamt }})
            &lt;/a&gt;
            &lt;a href="/?filter=offen" class="btn btn-outline-warning {% if filter == 'offen' %}active{% endif %}"&gt;
                Offen ({{ offen }})
            &lt;/a&gt;
            &lt;a href="/?filter=erledigt" class="btn btn-outline-success {% if filter == 'erledigt' %}active{% endif %}"&gt;
                Erledigt ({{ fertig }})
            &lt;/a&gt;
        &lt;/div&gt;

        &lt;!-- To-Do Liste --&gt;
        {% if todos %}
            &lt;div class="list-group"&gt;
                {% for todo in todos %}
                    &lt;div class="list-group-item"&gt;
                        &lt;div class="d-flex justify-content-between align-items-center"&gt;
                            &lt;div class="flex-grow-1"&gt;
                                &lt;!-- Checkbox zum Toggle --&gt;
                                &lt;form method="POST" action="/toggle/{{ todo.id }}" style="display:inline;"&gt;
                                    &lt;button type="submit" class="btn btn-link p-0 me-2" style="text-decoration:none;"&gt;
                                        {% if todo.erledigt %}
                                            ☑️
                                        {% else %}
                                            ☐
                                        {% endif %}
                                    &lt;/button&gt;
                                &lt;/form&gt;

                                &lt;!-- Aufgabentitel (mit Durchstrich wenn erledigt) --&gt;
                                &lt;span class="{% if todo.erledigt %}erledigt{% endif %}"&gt;
                                    {{ todo.aufgabe }}
                                &lt;/span&gt;

                                &lt;!-- Datum --&gt;
                                &lt;br&gt;
                                &lt;small class="text-muted"&gt;
                                    📅 {{ todo.erstellt[:10] }} um {{ todo.erstellt[11:16] }} Uhr
                                &lt;/small&gt;
                            &lt;/div&gt;

                            &lt;!-- Löschen Button --&gt;
                            &lt;form method="POST" action="/loeschen/{{ todo.id }}" style="display:inline;"&gt;
                                &lt;button type="submit" class="btn btn-sm btn-danger"
                                    onclick="return confirm('Wirklich löschen?')"&gt;
                                    🗑️ Löschen
                                &lt;/button&gt;
                            &lt;/form&gt;
                        &lt;/div&gt;
                    &lt;/div&gt;
                {% endfor %}
            &lt;/div&gt;
        {% else %}
            &lt;div class="alert alert-info"&gt;
                {% if filter == 'offen' %}
                    🎉 Keine offenen Aufgaben! Guter Job!
                {% elif filter == 'erledigt' %}
                    Noch keine erledigten Aufgaben.
                {% else %}
                    Keine Aufgaben vorhanden. Füge eine neue hinzu!
                {% endif %}
            &lt;/div&gt;
        {% endif %}
    &lt;/div&gt;
&lt;/body&gt;
&lt;/html&gt;
templates/todo_form.html
&lt;!DOCTYPE html&gt;
&lt;html lang="de"&gt;
&lt;head&gt;
    &lt;meta charset="UTF-8"&gt;
    &lt;meta name="viewport" content="width=device-width, initial-scale=1.0"&gt;
    &lt;title&gt;Neue Aufgabe&lt;/title&gt;
    &lt;link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css" rel="stylesheet"&gt;
&lt;/head&gt;
&lt;body&gt;
    &lt;div class="container mt-4"&gt;
        &lt;div class="row"&gt;
            &lt;div class="col-md-6 offset-md-3"&gt;
                &lt;h1&gt;✏️ Neue Aufgabe&lt;/h1&gt;

                &lt;!-- Flash Messages --&gt;
                {% with messages = get_flashed_messages(with_categories=true) %}
                    {% if messages %}
                        {% for category, message in messages %}
                            &lt;div class="alert alert-{{ category }} alert-dismissible fade show"&gt;
                                {{ message }}
                                &lt;button type="button" class="btn-close" data-bs-dismiss="alert"&gt;&lt;/button&gt;
                            &lt;/div&gt;
                        {% endfor %}
                    {% endif %}
                {% endwith %}

                &lt;form method="POST" class="needs-validation"&gt;
                    &lt;div class="mb-3"&gt;
                        &lt;label for="aufgabe" class="form-label"&gt;Aufgabe&lt;/label&gt;
                        &lt;input
                            type="text"
                            class="form-control"
                            id="aufgabe"
                            name="aufgabe"
                            placeholder="z.B. Einkaufen gehen..."
                            required
                            autofocus
                        &gt;
                        &lt;small class="text-muted"&gt;Mindestens 3 Zeichen erforderlich&lt;/small&gt;
                    &lt;/div&gt;

                    &lt;button type="submit" class="btn btn-success w-100"&gt;
                        ➕ Aufgabe hinzufügen
                    &lt;/button&gt;
                    &lt;a href="/" class="btn btn-secondary w-100 mt-2"&gt;
                        Abbrechen
                    &lt;/a&gt;
                &lt;/form&gt;
            &lt;/div&gt;
        &lt;/div&gt;
    &lt;/div&gt;
&lt;/body&gt;
&lt;/html&gt;
Features der To-Do-App: - Filter: Alle / Offen / Erledigt - filtern direkt in der Datenbank - Checkboxes: ☐/☑ zum schnellen Toggle ohne eigene Seite - Strikethrough: Erledigte Aufgaben visuell unterscheiden - Statistiken: Live-Zähler auf der Hauptseite - Datumsspeicherung: Automatic CURRENT_TIMESTAMP - Löschen mit Bestätigung: JavaScript confirm() - Validierung: Aufgabe muss mindestens 3 Zeichen sein - Bootstrap-Styling: Moderne, responsive UI mit List Groups
